for (let i = 1; i <= 4; i++) {
  governor.recordIteration('agent1', 'simple');
  const status = governor.getStatus('agent1');
  console.log(`Iteration ${i}: ${status.iterations}/${status.limit} (${status.limitPercentage}%)`);
}
console.log('');

// Test 4: Warning threshold should be reached
